/// <summary>
/// Filters and limits time parts to the requested precision.
/// Uses a direct loop instead of chained LINQ to avoid enumerator allocations.
/// </summary>
private static List<string?> SetPrecisionOfTimeSpan(
    List<string?> timeParts, int precision, bool countEmptyUnits)
{
    var result = new List<string?>(precision);
    int counted = 0;

    for (int i = 0; i < timeParts.Count && counted < precision; i++)
    {
        var part = timeParts[i];
        if (countEmptyUnits)
        {
            counted++;
            if (part != null) result.Add(part);
        }
        else
        {
            if (part != null)
            {
                result.Add(part);
                counted++;
            }
        }
    }

    return result;
}

